starterCode.css:
.page {
  display: grid;
  grid-template-columns: 200px 1fr;
  /* Define grid-template-rows: auto 1fr auto */
  /* Define grid-template-areas with header, nav, main, footer */
  min-height: 100vh;
}

header { background: #3498db; padding: 20px; }
nav { background: #2c3e50; color: white; padding: 20px; }
main { background: #ecf0f1; padding: 20px; color: #333; }
footer { background: #34495e; color: white; padding: 20px; }

/* Use grid-area on each element */

solution.css:
.page { display: grid; grid-template-columns: 200px 1fr; grid-template-rows: auto 1fr auto; grid-template-areas: 'header header' 'nav main' 'footer footer'; min-height: 100vh; }
header { grid-area: header; }
nav { grid-area: nav; }
main { grid-area: main; }
footer { grid-area: footer; }

starterCode.css:
.magazine {
  display: grid;
  gap: 16px;
  max-width: 1200px; margin: 0 auto;
}

/* Desktop: 3-column layout */
.magazine {
  grid-template-columns: 2fr 1fr 1fr;
  grid-template-areas:
    "featured featured sidebar"
    "art1     art2     sidebar"
    "footer   footer   footer";
}

.featured { grid-area: featured; background: #ffd700; padding: 20px; }
aside { grid-area: sidebar; background: #6c5ce7; color: white; padding: 20px; }
.article1 { grid-area: art1; background: #f0f0f0; padding: 20px; }
.article2 { grid-area: art2; background: #f0f0f0; padding: 20px; }
footer { grid-area: footer; background: #2c3e50; color: white; padding: 20px; }

/* Add tablet breakpoint (max-width: 900px) — switch to 2 columns */
/* Add mobile breakpoint (max-width: 600px) — switch to 1 column */

solution.css:
.magazine { display: grid; gap: 16px; max-width: 1200px; margin: 0 auto; grid-template-columns: 2fr 1fr 1fr; grid-template-areas: 'featured featured sidebar' 'art1 art2 sidebar' 'footer footer footer'; }
.featured { grid-area: featured; background: #ffd700; padding: 20px; }
aside { grid-area: sidebar; background: #6c5ce7; color: white; padding: 20px; }
.article1 { grid-area: art1; background: #f0f0f0; padding: 20px; }
.article2 { grid-area: art2; background: #f0f0f0; padding: 20px; }
footer { grid-area: footer; background: #2c3e50; color: white; padding: 20px; }
@media(max-width:900px){.magazine{grid-template-columns:1fr 1fr;grid-template-areas:'featured featured' 'art1 sidebar' 'art2 sidebar' 'footer footer';}}
@media(max-width:600px){.magazine{grid-template-columns:1fr;grid-template-areas:'featured' 'sidebar' 'art1' 'art2' 'footer';}}

starterCode.css:
.dashboard {
  display: grid;
  gap: 8px;
  height: 100vh;
  /* Define grid-template-columns, rows, and areas */
}

.toolbar { grid-area: toolbar; background: #2c3e50; color: white; padding: 15px; }
.sidebar { grid-area: sidebar; background: #34495e; color: white; padding: 15px; }
.chart { grid-area: chart; background: #ecf0f1; color: #333; padding: 15px; }
.notifications { grid-area: notifs; background: #e74c3c; color: white; padding: 15px; }
.stats { grid-area: stats; background: #27ae60; color: white; padding: 15px; }

/* Desktop layout:
   ┌────────────┬─────────────────┬─────────┐
   │  toolbar   │    toolbar      │ toolbar │
   ├────────────┼─────────────────┼─────────┤
   │  sidebar   │     chart       │  notifs │
   │            │                 │         │
   ├────────────┼─────────────────┼─────────┤
   │  sidebar   │     stats       │  notifs │
   └────────────┴─────────────────┴─────────┘
*/

/* Mobile: single column stack */

solution.css:
.dashboard { display: grid; gap: 8px; height: 100vh; grid-template-columns: 200px 1fr 200px; grid-template-rows: auto 1fr auto; grid-template-areas: 'toolbar toolbar toolbar' 'sidebar chart notifs' 'sidebar stats notifs'; }
.toolbar { grid-area: toolbar; background: #2c3e50; color: white; padding: 15px; }
.sidebar { grid-area: sidebar; background: #34495e; color: white; padding: 15px; }
.chart { grid-area: chart; background: #ecf0f1; color: #333; padding: 15px; }
.notifications { grid-area: notifs; background: #e74c3c; color: white; padding: 15px; }
.stats { grid-area: stats; background: #27ae60; color: white; padding: 15px; }
@media(max-width:768px){.dashboard{grid-template-columns:1fr;grid-template-rows:auto;grid-template-areas:'toolbar' 'sidebar' 'chart' 'notifs' 'stats';height:auto;}}
